9	      email: "newuser@example.com",
10	      password: "mypassword",
11	    });
12	    expect(res.status).toBe(201);
13	    expect(res.body).toHaveProperty("token");
14	    expect(typeof res.body.token).toBe("string");
15	    expect(res.body.token.split(".").length).toBe(3); // JWT has 3 parts
16	    expect(res.body).toHaveProperty("user");
17	    expect(res.body.user.username).toBe("newuser");
18	    expect(res.body.user.email).toBe("newuser@example.com");
19	    // Should not return the password
20	    expect(res.body.user).not.toHaveProperty("password");
21	  });
22	
23	  it("POST /auth/register should reject duplicate username", async () => {
24	    const res = await request(app).post("/auth/register").send({
25	      username: "alice",
