  const newPost: Post = { id: nextId(posts), title, content, userId: req.user!.id, createdAt: new Date().toISOString() };
  posts.push(newPost);
  res.status(201).json(newPost);
});

// PUT /:id — protected + ownership
router.put("/:id", authenticate, (req, res) => {
  const id = parseInt(req.params.id, 10);
  const index = posts.findIndex((p) => p.id === id);
  if (index === -1) { res.status(404).json({ error: "Post not found" }); return; }
  if (posts[index].userId !== req.user!.id) { res.status(403).json({ error: "Forbidden" }); return; }
  const { title, content } = req.body;
  if (title) posts[index].title = title;
  if (content) posts[index].content = content;
  res.json(posts[index]);
});

// DELETE /:id — protected + ownership
router.delete("/:id", authenticate, (req, res) => {
  const id = parseInt(req.params.id, 10);
  const index = posts.findIndex((p) => p.id === id);
  if (index === -1) { res.status(404).json({ error: "Post not found" }); return; }
  if (posts[index].userId !== req.user!.id) { res.status(403).json({ error: "Forbidden" }); return; }
  res.json(posts.splice(index, 1)[0]);
});
```

GET handlers stay unchanged (public).

---

### 6. `src/routes/comments.ts` — Auth middleware + ownership checks

Changes:
- Import `authenticate` from `"../middleware/auth.js"`.
- `POST /posts/:postId/comments`: add `authenticate`, replace `userId: userId || 1` with `userId: req.user!.id`.
- `PUT /comments/:id`: add `authenticate` (no ownership test exists but logically consistent).
- `DELETE /comments/:id`: add `authenticate` + ownership check (403 if `comments[index].userId !== req.user!.id`).

GET handlers stay unchanged (public).

---

## Files NOT Changed

- `src/types.ts` — existing `User`, `Post`, `Comment` interfaces are correct as-is.
- `src/db.ts` — seed data and `nextId()` helper are sufficient.
- `src/server.ts` — no changes needed.
- `src/middleware/logger.ts` — no changes needed.

---

## Implementation Order

1. `src/express.d.ts` (no dependencies)
2. `src/middleware/auth.ts` (depends on `jsonwebtoken` only)
3. `src/routes/auth.ts` (depends on step 2 for `JWT_SECRET`)
4. `src/routes/posts.ts` (depends on step 2)
5. `src/routes/comments.ts` (depends on step 2)
6. `src/app.ts` (depends on step 3)

---

## Key Gotchas

| Risk | Mitigation |
|---|---|
| `src/express.d.ts` must be script-scope | No `import`/`export` in that file |
| ES module imports need `.js` extension | Use `from "../middleware/auth.js"` (not `.ts`) |
| `jwt.verify` return type | Cast: `as { id: number; username: string }` |
| `userId` from token, not body | Replace `userId || 1` with `req.user!.id` in POST handlers |
| 401 vs 403 | Middleware returns 401; ownership violations return 403 |
| Register response omits password | Construct explicit `{ id, username, email }` object, not spread |

---

## Verification

Run: `npm test`

Expected: all tests in `tests/auth.test.ts`, `tests/posts.test.ts`, and `tests/comments.test.ts` pass.

- `posts.test.ts` — GET-only tests, unaffected by auth changes ✓
- `comments.test.ts` — GET-only tests, unaffected by auth changes ✓  
- `auth.test.ts` — 20 tests covering register, login, 401 protection, and 403 ownership enforcement ✓

